             <div className="flex bg-white shadow-sm overflow-hidden rounded-sm flex-1 sm:flex-none">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    type="button"
                    onClick={() => handleSourceLangChange(full)}
                    className={`flex-1 sm:flex-none px-4 py-2.5 text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
             <button 
                type="button" 
                onClick={swapLanguages}
                className="text-stone-300 hover:text-[#7c1a1a] transition-all p-1.5 hover:rotate-180 duration-500"
              >
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="flex bg-white shadow-sm overflow-hidden rounded-sm flex-1 sm:flex-none">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    type="button"
                    onClick={() => handleTargetLangChange(full)}
                    className={`flex-1 sm:flex-none px-4 py-2.5 text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>

          <div className="flex items-center gap-4">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-black">Audio Sync</span>
            <button 
              onClick={() => setAutoAudio(!autoAudio)}
              className={`w-12 h-6 rounded-full relative transition-all duration-300 p-1 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}
            >
