            onChange={(e) => setQuery(e.target.value)}
            placeholder="Summon an inscription..."
            className="flex-1 text-4xl md:text-8xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-100 lowercase font-medium tracking-tighter leading-[1.1] pt-1"
